-- ============================================================
-- MercuryGate Locations Table (Active + Inactive)
-- Run in Supabase Studio at http://127.0.0.1:54323
-- ============================================================

CREATE TABLE IF NOT EXISTS mg_locations (
  id              bigserial PRIMARY KEY,
  owner           text,
  location_code   text,
  active          boolean DEFAULT true,
  location_type   text,
  residential     boolean DEFAULT false,
  name            text NOT NULL,
  address1        text,
  address2        text,
  city            text,
  state           text,
  postal_code     text,
  country         text,
  lat             numeric,
  lon             numeric,
  docks           text,
  references      text,
  services        text,
  validated       boolean DEFAULT false,
  created_at      timestamptz DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_mg_locations_name   ON mg_locations(name);
CREATE INDEX IF NOT EXISTS idx_mg_locations_city   ON mg_locations(city, state);
CREATE INDEX IF NOT EXISTS idx_mg_locations_type   ON mg_locations(location_type);
CREATE INDEX IF NOT EXISTS idx_mg_locations_active ON mg_locations(active);
CREATE INDEX IF NOT EXISTS idx_mg_locations_geo    ON mg_locations(lat, lon)
  WHERE lat IS NOT NULL AND lon IS NOT NULL;

